-                if let Some(Commands::Pages {
-                    include_attachments,
-                    ..
-                }) = &parsed.command
-                {
-                    assert!(include_attachments, "flag should be true when passed");
-                } else {
-                    panic!("expected Pages command");
-                }
-            }
-        });
-    }
